    ...data,
    prompts: {
      system: systemPrompt,
      user: userPrompt
    }
  }
}];

const gptResponse = $input.first().json;
const dataOriginal = $('Constructor Prompt Producto').first().json;

let contenido;
try {
  let responseText = gptResponse.choices[0].message.content;
  responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  contenido = JSON.parse(responseText);
} catch (error) {
  throw new Error('Error parseando respuesta de ChatGPT: ' + error.message);
}

if (!contenido.seo || !contenido.hero || !contenido.especificaciones) {
  throw new Error('Respuesta de ChatGPT incompleta');
}

return [{
  json: {
    ...dataOriginal,
    contenido: contenido
  }
}];

// ═══════════════════════════════════════════════════════════════════════════════
// CONSTRUCTOR DE PROMPTS PARA 4 IMAGENES - FAL.AI (SECUENCIAL)
// v1.1 - Ejecucion secuencial para evitar errores de paralelismo
// ═══════════════════════════════════════════════════════════════════════════════

const data = $input.first().json;
const p = data.producto;
const timestamp = data.timestamp;

const basePrompt = 'Professional product photography, studio lighting, white background, high resolution 4K, commercial product shot, clean minimal style, ';

const imagePrompts = [
  {
    tipo: 'principal',
    prompt: basePrompt + p.imagenesContexto.principal,
    filename: `${p.slug}-principal-${timestamp}.jpg`
  },
  {
    tipo: 'lateral',
    prompt: basePrompt + p.imagenesContexto.lateral,
    filename: `${p.slug}-lateral-${timestamp}.jpg`
  },
  {
    tipo: 'detalle',
    prompt: basePrompt + p.imagenesContexto.detalle,
    filename: `${p.slug}-detalle-${timestamp}.jpg`
  },
  {
    tipo: 'uso',
    prompt: basePrompt + p.imagenesContexto.uso,
    filename: `${p.slug}-uso-${timestamp}.jpg`
  }
];

// Inicializar objeto para acumular URLs de imagenes
return [{
  json: {
    ...data,
    imagenes: imagePrompts,
    imagenesUrls: {},
    imagenesFilenames: {
      principal: imagePrompts[0].filename,
      lateral: imagePrompts[1].filename,
      detalle: imagePrompts[2].filename,
      uso: imagePrompts[3].filename
    },
    currentPrompt: imagePrompts[0].prompt,
    currentTipo: 'principal'
  }
}];

// Procesar resultado de Imagen 1 y preparar para Imagen 2
const falResponse = $input.first().json;
const dataOriginal = $('Constructor FAL Prompts').first().json;

const imageUrl = falResponse?.images?.[0]?.url;
if (!imageUrl) {
  throw new Error('No se obtuvo URL de imagen 1 de FAL.ai');
}

return [{
  json: {
    ...dataOriginal,
    imagenesUrls: {
      principal: imageUrl
    },
    currentPrompt: dataOriginal.imagenes[1].prompt,
    currentTipo: 'lateral'
  }
}];

// Procesar resultado de Imagen 2 y preparar para Imagen 3
const falResponse = $input.first().json;
const dataOriginal = $('Procesar Imagen 1').first().json;

const imageUrl = falResponse?.images?.[0]?.url;
if (!imageUrl) {
  throw new Error('No se obtuvo URL de imagen 2 de FAL.ai');
}

return [{
  json: {
    ...dataOriginal,
    imagenesUrls: {
      ...dataOriginal.imagenesUrls,
      lateral: imageUrl
    },
    currentPrompt: dataOriginal.imagenes[2].prompt,
    currentTipo: 'detalle'
  }
}];

// Procesar resultado de Imagen 3 y preparar para Imagen 4
const falResponse = $input.first().json;
const dataOriginal = $('Procesar Imagen 2').first().json;

const imageUrl = falResponse?.images?.[0]?.url;
if (!imageUrl) {
  throw new Error('No se obtuvo URL de imagen 3 de FAL.ai');
}

return [{
  json: {
    ...dataOriginal,
    imagenesUrls: {
      ...dataOriginal.imagenesUrls,
      detalle: imageUrl
    },
    currentPrompt: dataOriginal.imagenes[3].prompt,
    currentTipo: 'uso'
  }
}];

// Procesar resultado de Imagen 4 - TODAS LAS IMAGENES COMPLETADAS
const falResponse = $input.first().json;
const dataOriginal = $('Procesar Imagen 3').first().json;

const imageUrl = falResponse?.images?.[0]?.url;
if (!imageUrl) {
  throw new Error('No se obtuvo URL de imagen 4 de FAL.ai');
}

// Ahora tenemos las 4 URLs de imagenes
const imagenesUrlsCompletas = {
  ...dataOriginal.imagenesUrls,
  uso: imageUrl
};

// Validar que tenemos las 4
if (!imagenesUrlsCompletas.principal || !imagenesUrlsCompletas.lateral || 
    !imagenesUrlsCompletas.detalle || !imagenesUrlsCompletas.uso) {
  throw new Error('No se obtuvieron todas las 4 imagenes de FAL.ai');
}

return [{
  json: {
    ...dataOriginal,
    imagenesUrls: imagenesUrlsCompletas
  }
}];

// Guardar binario de imagen 1 y continuar
const downloadResult = $input.first();
const dataOriginal = $('Procesar Imagen 4 Final').first().json;

const binaryData = downloadResult.binary?.data?.data;
if (!binaryData) {
  throw new Error('No se pudo descargar imagen 1');
}

return [{
  json: {
    ...dataOriginal,
    imagenesBase64: {
      principal: binaryData
    }
  }
}];

// Guardar binario de imagen 2 y continuar
const downloadResult = $input.first();
const dataOriginal = $('Guardar Imagen 1').first().json;

const binaryData = downloadResult.binary?.data?.data;
if (!binaryData) {
  throw new Error('No se pudo descargar imagen 2');
}

return [{
  json: {
    ...dataOriginal,
    imagenesBase64: {
      ...dataOriginal.imagenesBase64,
      lateral: binaryData
    }
  }
}];

// Guardar binario de imagen 3 y continuar
const downloadResult = $input.first();
const dataOriginal = $('Guardar Imagen 2').first().json;

const binaryData = downloadResult.binary?.data?.data;
if (!binaryData) {
  throw new Error('No se pudo descargar imagen 3');
}

return [{
  json: {
    ...dataOriginal,
    imagenesBase64: {
      ...dataOriginal.imagenesBase64,
      detalle: binaryData
    }
  }
}];

// Guardar binario de imagen 4 - TODAS LAS DESCARGAS COMPLETADAS
const downloadResult = $input.first();
const dataOriginal = $('Guardar Imagen 3').first().json;

const binaryData = downloadResult.binary?.data?.data;
if (!binaryData) {
  throw new Error('No se pudo descargar imagen 4');
}

const imagenesBase64Completas = {
  ...dataOriginal.imagenesBase64,
  uso: binaryData
};

// Validar que tenemos las 4
if (!imagenesBase64Completas.principal || !imagenesBase64Completas.lateral || 
    !imagenesBase64Completas.detalle || !imagenesBase64Completas.uso) {
  throw new Error('No se descargaron todas las 4 imagenes');
}

return [{
  json: {
    ...dataOriginal,
    imagenesBase64: imagenesBase64Completas
  }
}];

// Preparar datos despues de subir imagen 1
const dataOriginal = $('Guardar Imagen 4 Final').first().json;

return [{
  json: {
    ...dataOriginal,
    img1Subida: true
  }
}];

// Preparar datos despues de subir imagen 2
const dataOriginal = $('Prep Subir Img 2').first().json;

return [{
  json: {
    ...dataOriginal,
    img2Subida: true
  }
}];

// Preparar datos despues de subir imagen 3
const dataOriginal = $('Prep Subir Img 3').first().json;

return [{
  json: {
    ...dataOriginal,
    img3Subida: true
  }
}];

// Consolidar despues de subir todas las imagenes
const dataOriginal = $('Prep Subir Img 4').first().json;

return [{
  json: {
    ...dataOriginal,
    imagenesSubidas: true
  }
}];

